import java.sql.*;

public class SecureSQLInjection {
    public static void main(String[] args) {
        String username = args[0]; // Assume user input is directly used without validation
        String password = args[1]; // Assume user input is directly used without validation

        try {
            Connection connection = DriverManager.getConnection("jdbc:mysql://localhost:3306/mydatabase", "root", "password");

            String query = "SELECT * FROM users WHERE username=? AND password=?";
            PreparedStatement statement = connection.prepareStatement(query);
            statement.setString(1, username);
            statement.setString(2, password);

            ResultSet resultSet = statement.executeQuery();

            if (resultSet.next()) {
                System.out.println("Logged in successfully as: " + resultSet.getString("username"));
            } else {
                System.out.println("Login failed");
            }

            connection.close();
        } catch (SQLException e) {
            e.printStackTrace();
        }
    }
}

